# fix_crm_remaining_dark.ps1 - Evaluacion, Tarifarios, Historia360
Write-Host "Aplicando dark mode a tabs restantes CRM..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\crm\components\Evaluation\EvaluationPanel.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/modules/crm/components/Evaluation/EvaluationPanel.tsx" -ForegroundColor Yellow

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\crm\components\Tariffs\TariffsPanel.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/modules/crm/components/Tariffs/TariffsPanel.tsx" -ForegroundColor Yellow

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\crm\components\History360\History360Panel.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/modules/crm/components/History360/History360Panel.tsx" -ForegroundColor Yellow

Write-Host "Todos los tabs del CRM con dark mode!" -ForegroundColor Green
